SELECT

FROM goods g
LEFT JOIN user u ON g.seller_id = u.id
LEFT JOIN shop_category c ON g.category_id = c.id


        AND g.goods_name LIKE CONCAT('%', #{goodsName}, '%')


        AND g.category_id = #{categoryId}


        AND g.goods_status = #{goodsStatus}


        AND g.is_new = #{isNew}


        AND g.sell_price >= #{minPrice}


        AND g.sell_price <= #{maxPrice}


        AND g.seller_id = #{sellerId}


ORDER BY g.create_time

