UPDATE goods
goods_name = #{goodsName}, goods_desc = #{goodsDesc}, goods_pic = #{goodsPic}, category_id = #{categoryId}, original_price = #{originalPrice}, sell_price = #{sellPrice}, goods_status = #{goodsStatus}, is_new = #{isNew}, stock = #{stock}, update_time = #{updateTime}
WHERE id = #{id}

UPDATE goods
SET goods_status = #{status}, update_time = #{updateTime}
WHERE id = #{id}
